import React, { useEffect, useState } from "react";
import api from "../services/api";

function Dealers() {
  const [dealers, setDealers] = useState([]);

  useEffect(() => {
    api.get("dealers/")
      .then((res) => setDealers(res.data))
      .catch((err) => console.error(err));
  }, []);

  return (
    <div>
      <h2>Dealers</h2>
      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Dealer Code</th>
            <th>Email</th>
          </tr>
        </thead>
        <tbody>
          {dealers.map((item) => (
            <tr key={item.id}>
              <td>{item.id}</td>
              <td>{item.name}</td>
              <td>{item.dealer_code}</td>
              <td>{item.email}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Dealers;
